# ── Histórico de Preços ────────────────────────────────────────────

def _db_gravar_preco(cnpj: str, razao_social: str, municipio: str, uf: str,
                     combustivel: str, preco: float, fonte: str = "PP",
                     lat: float = None, lon: float = None,
                     data_ref: str = None) -> bool:
    """Grava snapshot de preço no histórico. Ignora duplicatas (cnpj + combustivel + data_ref)."""
    db = _db_client()
    if not db or not cnpj or not preco:
        return False
    try:
        _payload = {
            "cnpj":         cnpj,
            "razao_social": razao_social or "",
            "municipio":    municipio or "",
            "uf":           uf or "",
            "combustivel":  combustivel,
            "preco":        round(float(preco), 3),
            "fonte":        fonte,
            "data_ref":     data_ref or datetime.now().strftime("%Y-%m-%d"),
            "lat":          lat,
            "lon":          lon,
        }
        _eid = _db_empresa_id()
        if _eid:
            _payload["empresa_id"] = _eid
        db.table("historico_precos").upsert(
            _payload, on_conflict="cnpj,combustivel,data_ref"
        ).execute()
        return True
    except Exception:
        return False


def _db_historico_preco(cnpj: str, combustivel: str = None, dias: int = 90) -> list:
    """Retorna histórico de preços de um posto nos últimos N dias."""
    db = _db_client()
    if not db:
        return []
    try:
        from datetime import timedelta
        data_ini = (datetime.now() - timedelta(days=dias)).strftime("%Y-%m-%d")
        q = db.table("historico_precos") \
              .select("data_ref,preco,combustivel,fonte") \
              .eq("cnpj", cnpj) \
              .gte("data_ref", data_ini) \
              .order("data_ref")
        if combustivel:
            q = q.eq("combustivel", combustivel)
        res = q.execute()
        return res.data or []
    except Exception:
        return []


# ── Controle de Acesso (Allowlist / Blacklist) ────────────────────

# E-mail do administrador — único com acesso ao painel de gestão
_ADMIN_EMAIL = "d.peruffo@gmail.com"


# ═══════════════════════════════════════════════════════════════════
#  MULTI-TENANCY — Isolamento de dados por empresa
# ═══════════════════════════════════════════════════════════════════

def _is_admin() -> bool:
    """Retorna True se o usuário logado é o administrador global."""
    _email = (st.session_state.get("_auth_user") or {}).get("email", "")
    return _email.lower() == _ADMIN_EMAIL.lower()


def _db_empresa_id() -> str | None:
    """
    Retorna o empresa_id ativo da sessão.
    Admin → None (sem filtro, vê tudo).
    Usuário normal → UUID da empresa selecionada.
    """
    if _is_admin():
        # Admin pode forçar filtro por empresa via seletor especial
        return st.session_state.get("_admin_empresa_filtro", None)
    return (st.session_state.get("_empresa_ativa") or {}).get("id")


def _db_empresa_nome() -> str:
    """Retorna o nome da empresa ativa (ou 'Todas as Empresas' para admin sem filtro)."""
    if _is_admin():
        _filtro = st.session_state.get("_admin_empresa_filtro")
        if not _filtro:
            return "Todas as Empresas"
        # Busca nome da empresa filtrada
        for _e in st.session_state.get("_todas_empresas", []):
            if _e["id"] == _filtro:
                return _e["nome"]
        return "Empresa selecionada"
    return (st.session_state.get("_empresa_ativa") or {}).get("nome", "—")


def _db_resolver_empresas(email: str) -> list:
    """
    Retorna lista de empresas associadas ao e-mail.
    Cada item: {"id": uuid_str, "nome": str, "role": str}
    Retorna [] se nenhuma empresa cadastrada.
    """
    db = _db_client()
    if not db:
        return []
    try:
        _res = (
            db.table("usuarios_empresas")
            # Fase 1: inclui plano, status e trial_ends_at para feature flags e banners
            .select("empresa_id, role, empresas(id, nome, ativo, plano, status, trial_ends_at, max_usuarios, max_veiculos)")
            .eq("user_email", email.lower())
            .eq("ativo", True)
            .execute()
        )
        _empresas = []
        for _row in (_res.data or []):
            _emp = _row.get("empresas") or {}
            if _emp and _emp.get("ativo"):
                _empresas.append({
                    "id":            _emp["id"],
                    "nome":          _emp["nome"],
                    "role":          _row.get("role", "viewer"),
                    # Fase 1: campos de plano para feature flags e banners
                    "plano":         _emp.get("plano", "gratuito"),
                    "status":        _emp.get("status", "ativo"),
                    "trial_ends_at": _emp.get("trial_ends_at"),
                    "max_usuarios":  _emp.get("max_usuarios", 1),
                    "max_veiculos":  _emp.get("max_veiculos", 10),
                })
        return _empresas
    except Exception:
        return []


