_chips_rendered_run: set = set()  # reset a cada rerun do Streamlit

def _get_periodo_dias(default: int = 90) -> int:
    """
    Retorna o número de dias selecionado pelo usuário nos chips de período.
    Usa session_state["_chip_periodo_dias"] se definido, senão retorna default.
    Garante que o período sempre se refere a data_abastecimento.
    """
    v = st.session_state.get("_chip_periodo_dias")
    if v is not None:
        try:
            return int(v)
        except (TypeError, ValueError):
            pass
    return default


def _render_filtros_inteligentes(modo: str) -> None:
    """Renderiza chips de filtros inteligentes contextuais por modo."""
    global _chips_rendered_run

    # ── Detecta troca de modo e limpa chips para evitar contaminação ──
    # Executa apenas uma vez por rerun (antes de adicionar ao set)
    if modo not in _chips_rendered_run:
        _last = st.session_state.get("_last_chip_modo", "")
        if _last != modo:
            for _ck in ["_chip_combustivel", "_chip_periodo_dias", "_chip_uf_busca"]:
                st.session_state.pop(_ck, None)
            st.session_state["_last_chip_modo"] = modo

    if modo in _chips_rendered_run:
        return
    _chips_rendered_run.add(modo)
    chips_modo = _CHIPS_CONFIG.get(modo, {})
    if not chips_modo:
        return
    st.markdown(_CHIPS_CSS, unsafe_allow_html=True)
    st.markdown("<div class=\'fi-header\'>💡 Filtros sugeridos</div>",
                unsafe_allow_html=True)
    for grupo, opcoes in chips_modo.items():
        st.markdown(f"<div class=\'fi-group-label\'>{grupo}</div>",
                    unsafe_allow_html=True)
        _ncols = min(len(opcoes), 4)
        _cols  = st.columns(_ncols)
        for i, (label, sk, valor) in enumerate(opcoes):
            _ativo = st.session_state.get(sk) == valor
            with _cols[i % _ncols]:
                if st.button(
                    f"{'✓ ' if _ativo else ''}{label}",
                    key=f"chip_{modo}_{sk}_{label}",
                    type="primary" if _ativo else "secondary",
                    use_container_width=True,
                ):
                    if _ativo:
                        st.session_state.pop(sk, None)
                    else:
                        st.session_state[sk] = valor
                        if sk == "_restore_uf":
                            st.session_state["_form_key_m1"] = (
                                st.session_state.get("_form_key_m1", 0) + 1
                            )
                    st.rerun()
    st.markdown(
        "<hr style=\'margin:6px 0 10px;opacity:0.15\'>",
        unsafe_allow_html=True,
    )

